import functools


class CountCalls:
    """Count how many times the decorated function has been called."""

    def __init__(self, fn):
        functools.update_wrapper(self, fn)
        self.fn = fn
        self.count = 0

    def __call__(self, *args, **kwargs):
        self.count += 1
        return self.fn(*args, **kwargs)


@CountCalls
def embed(text: str) -> list[float]:
    # stub: returns a fixed vector
    return [0.1, 0.2, 0.3]


embed("hello")
