import time
import threading
from collections import deque
from functools import wraps

# --- Shared tool registry ---
TOOLS: dict[str, callable] = {}


# --- Rate limiter: token bucket ---
class _TokenBucket:
    def __init__(self, rate: float, capacity: float):
        self._rate = rate          # tokens per second
        self._capacity = capacity
        self._tokens = capacity
        self._last = time.monotonic()
        self._lock = threading.Lock()

    def consume(self):
        with self._lock:
            now = time.monotonic()
            self._tokens = min(
                self._capacity,
                self._tokens + (now - self._last) * self._rate,
            )
            self._last = now
            if self._tokens < 1:
                raise RuntimeError("Rate limit exceeded")
            self._tokens -= 1


# --- Decorators ---
def register(name: str | None = None):
    def decorator(fn):
        TOOLS[name or fn.__name__] = fn
        return fn
    return decorator


def rate_limit(calls_per_second: float = 5.0):
    bucket = _TokenBucket(calls_per_second, calls_per_second)
    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            bucket.consume()
            return fn(*args, **kwargs)
        return wrapper
    return decorator


def traced(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        t0 = time.perf_counter()
        try:
            result = fn(*args, **kwargs)
            print(f"OK  {fn.__name__} {(time.perf_counter()-t0)*1e3:.1f}ms")
            return result
        except Exception as exc:
            print(f"ERR {fn.__name__} {(time.perf_counter()-t0)*1e3:.1f}ms {exc}")
            raise
    return wrapper


