import threading

def collect_calls(fn):
    local = threading.local()
    @wraps(fn)
    def wrapper(*args, **kwargs):
        if not hasattr(local, "calls"):
            local.calls = []
        local.calls.append(args)
        return fn(*args, **kwargs)
    return wrapper

