# tenacity retry with exponential backoff
from tenacity import retry, stop_after_attempt, wait_exponential, retry_if_exception_type
import httpx

@retry(
    stop=stop_after_attempt(5),
    wait=wait_exponential(multiplier=1, min=1, max=16),
    retry=retry_if_exception_type(httpx.HTTPStatusError),
    reraise=True,
)
def call_api(url: str) -> dict:
    response = httpx.get(url, timeout=10)
    response.raise_for_status()
    return response.json()

import os
from functools import wraps

# Sentinel-based mandatory-decorator enforcement
_REQUIRES_KEY = "__requires_api_key__"

def require_api_key(fn):
    """Mark fn as requiring a valid API key. Checked at dispatch time."""
    fn.__requires_api_key__ = True
    @wraps(fn)
    def wrapper(*args, **kwargs):
        key = os.environ.get("AGENT_API_KEY")
        if not key or len(key) < 16:
            raise PermissionError("Missing or invalid AGENT_API_KEY")
        return fn(*args, **kwargs)
    return wrapper


def register_tool(name: str | None = None):
    def decorator(fn):
        if not getattr(fn, _REQUIRES_KEY, False):
            raise RuntimeError(
                f"Tool {fn.__name__!r} must be decorated with @require_api_key before @register_tool"
            )
        TOOLS[name or fn.__name__] = fn
        return fn
    return decorator


@register_tool()        # raises RuntimeError — @require_api_key is missing
def unsafe_tool(): ...

@require_api_key        # correct order
@register_tool()
def safe_tool(): ...
